INSERT INTO `bot` VALUES ('17', '2', 'Bot1', '这个用户很神秘，什么都没有写...', 'package com.kob.botrunningsystem.utils;\n\nimport java.io.File;\nimport java.io.FileNotFoundException;\nimport java.util.ArrayList;\nimport java.util.List;\nimport java.util.Scanner;\n\npublic class Bot implements java.util.function.Supplier<Integer> {   // 因为要通过 Consumer 里的Reflect.compile()方法来编译，所以包名要加全来查找\n\n    static class Cell {\n        public int x, y;\n\n        public Cell(int x, int y) {\n            this.x = x;\n            this.y = y;\n        }\n    }\n\n    public boolean checkTailIncreasing(int step) {   // 判断蛇在某回合是否变长\n        if (step < 10) return true;\n        return step % 3 == 1;\n    }\n\n    // 将蛇的身体取出来\n    public List<Cell> getCells(int sx, int sy, String steps) {\n        steps = steps.substring(1, steps.length() - 1);\n        List<Cell> res = new ArrayList<>();\n\n        int[] dx = {-1, 0, 1, 0}, dy = {0, 1, 0, -1};\n        int x = sx, y = sy;\n        int step = 0;\n        res.add(new Cell(x, y));\n\n        for (int i = 0; i < steps.length(); i ++ ) {\n            int d = steps.charAt(i) - \'0\';\n            x += dx[d];\n            y += dy[d];\n            res.add(new Cell(x, y));\n            step ++;\n            if (!checkTailIncreasing(step)) {\n                res.remove(0);\n            }\n        }\n\n        return res;\n    }\n\n    public Integer nextMove(String input) {\n        String[] info = input.split(\"#\");\n\n        // 将编码的地图还原成一个二维数组\n        int[][] g = new int[13][14];\n        for (int i = 0, k = 0; i < 13; i ++ ) {\n            for (int j = 0; j < 14; j ++, k ++ ) {\n                if (info[0].charAt(k) == \'1\') {\n                    g[i][j] = 1;\n                }\n            }\n        }\n\n        int aSx = Integer.parseInt(info[1]), aSy = Integer.parseInt(info[2]);\n        int bSx = Integer.parseInt(info[4]), bSy = Integer.parseInt(info[5]);\n\n        List<Cell> snake1 = getCells(aSx, aSy, info[3]);\n        List<Cell> snake2 = getCells(bSx, bSy, info[6]);\n\n        for (Cell cell: snake1) g[cell.x][cell.y] = 1;\n        for (Cell cell: snake2) g[cell.x][cell.y] = 1;\n\n        int[] dx = {-1, 0, 1, 0}, dy = {0, 1, 0, -1};\n        for (int i = 0; i < 4; i ++ ) {\n            int x = snake1.get(snake1.size() - 1).x + dx[i];\n            int y = snake1.get(snake1.size() - 1).y + dy[i];\n            if (x >= 0 && x < 13 && y >= 0 && y < 14 && g[x][y] == 0) {\n                return i;\n            }\n        }\n\n        return 0;\n    }\n\n    @Override\n    public Integer get() {\n        File file = new File(\"input.txt\");\n        try {\n            Scanner sc = new Scanner(file);\n            return nextMove(sc.next());\n        } catch (FileNotFoundException e) {\n            throw new RuntimeException(e);\n        }\n    }\n}\n', '2023-06-23 17:01:15', '2023-09-24 22:14:14');
